import React, { useEffect, useMemo, useState } from "react";
import HeatmapGrid from "../components/HeatmapGrid";

const BACKEND = process.env.REACT_APP_BACKEND_URL || "http://localhost:5001";

export default function Summary() {
  const [data, setData] = useState({});
  const [error, setError] = useState("");

  useEffect(() => {
    fetch(`${BACKEND}/summary`)
      .then((r) => (r.ok ? r.json() : r.text().then((t) => Promise.reject(new Error(t)))))
      .then(setData)
      .catch((e) => setError(e.message));
  }, []);

  const entries = useMemo(() => Object.entries(data || {}), [data]);

  // simple counters
  const totals = useMemo(() => {
    let hazards = 0, defects = 0, recs = 0;
    for (const [, v] of entries) {
      const t = (v?.analysis || "").toLowerCase();
      hazards += (t.match(/\bhazard[s]?\b/g) || []).length;
      defects += (t.match(/\bdefect[s]?\b/g) || []).length;
      recs += (t.match(/\b(recommend|improvement|action)s?\b/g) || []).length;
    }
    return { hazards, defects, recs };
  }, [entries]);

  const maxCount = Math.max(totals.hazards, totals.defects, totals.recs, 1);

  // demo heatmap; you can replace with backend-provided matrix
  const rows = ["Critical", "Moderate", "Good"];
  const cols = ["0–33", "34–66", "67–100"];
  const matrix = [
    [totals.hazards, 0, 0],
    [0, totals.defects, 0],
    [0, 0, Math.max(1, entries.length - totals.hazards - totals.defects)],
  ];

  return (
    <main className="max-w-7xl mx-auto px-6 py-8">
      <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight text-slate-900">Inspection Report</h1>
      <p className="text-sm text-slate-500 mt-1">Generated by iShip Vessel Inspection AI • {new Date().toLocaleString()}</p>

      <div className="mt-6 grid grid-cols-1 md:grid-cols-[280px,1fr] gap-6">
        {/* Left */}
        <aside className="rounded-2xl border border-slate-200 bg-white p-4">
          <h3 className="text-slate-900 font-semibold mb-3">Contents</h3>
          <ol className="space-y-2 text-sm">
            <li className="px-3 py-2 rounded-lg bg-slate-100">1. Disclaimer</li>
            <li className="px-3 py-2 rounded-lg hover:bg-slate-50">2. Executive Summary</li>
            <li className="px-3 py-2 rounded-lg hover:bg-slate-50">3. Risk Heatmap</li>
            <li className="px-3 py-2 rounded-lg hover:bg-slate-50">4. Action Register</li>
            <li className="px-3 py-2 rounded-lg hover:bg-slate-50">5. Findings (per photo)</li>
          </ol>

          <div className="mt-6 rounded-xl border border-slate-200 p-4">
            <h4 className="font-semibold text-slate-900 mb-3">Summary Counters</h4>
            <Counter label="Hazards" value={totals.hazards} color="rose" max={maxCount} />
            <Counter label="Defects" value={totals.defects} color="amber" max={maxCount} />
            <Counter label="Recommendations" value={totals.recs} color="emerald" max={maxCount} />
          </div>
        </aside>

        {/* Right */}
        <section className="space-y-6">
          <article className="rounded-2xl border border-slate-200 bg-white p-6">
            <h2 className="text-xl font-bold text-slate-900">1) Disclaimer</h2>
            <p className="mt-2 text-slate-700">This report reflects the condition visible in the submitted photographs at the time of analysis. It does not replace statutory or class inspections. Findings and recommendations are generated by AI and should be reviewed by a qualified marine inspector prior to action.</p>
          </article>

          {/* Executive Summary */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <Card title="Photos analyzed" value={entries.length} tint="emerald" />
            <Card title="Total hazards" value={totals.hazards} tint="rose" />
            <Card title="Total defects" value={totals.defects} tint="amber" />
            <Card title="Recommendations" value={totals.recs} tint="sky" />
          </div>

          {/* Heatmap */}
          <article className="card">
            <h3 className="font-semibold text-slate-900">3) Risk Heatmap</h3>
            <p className="section-help">Distribution by <b>severity</b> (rows) vs <b>score</b> (columns).</p>
            <HeatmapGrid rows={rows} cols={cols} data={matrix} />
          </article>

          {/* Action Register */}
          <article className="rounded-2xl border border-slate-200 bg-white p-2 md:p-4">
            <h3 className="font-semibold text-slate-900 p-4">4) Action Register</h3>
            <div className="overflow-x-auto">
              <table className="min-w-full text-sm">
                <thead>
                  <tr className="text-left text-slate-500 border-b">
                    <th className="p-3">Action</th>
                    <th className="p-3">Linked Photo</th>
                    <th className="p-3">Severity</th>
                  </tr>
                </thead>
                <tbody>
                  {entries.map(([name, item]) => (
                    <tr key={name} className="border-b last:border-0">
                      <td className="p-3 text-slate-800"><strong>Recommendation:</strong> {cleanText(item.analysis)}</td>
                      <td className="p-3"><span className="text-sky-700 hover:underline cursor-pointer">{name}</span></td>
                      <td className="p-3">
                        <span className="px-2 py-1 rounded-full bg-amber-100 text-amber-700">Moderate</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </article>

          {/* Per-photo cards */}
          <article className="rounded-2xl border border-slate-200 bg-white p-6">
            <h3 className="font-semibold text-slate-900">5) Findings (per photo)</h3>
            <div className="mt-4 grid md:grid-cols-2 gap-6">
              {entries.map(([name, item]) => (
                <div key={name} className="rounded-xl border border-slate-200 p-4 bg-white">
                  <div className="flex gap-4">
                    <img src={item.path} alt={name} className="w-40 h-28 object-cover rounded-lg border border-slate-200"/>
                    <div className="flex-1">
                      <div className="flex items-center justify-between">
                        <h4 className="font-semibold text-slate-900 truncate">{name}</h4>
                        <span className="px-2 py-1 rounded-full bg-rose-100 text-rose-700 text-xs">AI Analysis</span>
                      </div>
                      <ul className="mt-2 list-disc pl-5 text-slate-700">
                        {splitBullets(cleanText(item.analysis)).map((b, i) => (<li key={i}>{b}</li>))}
                      </ul>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </article>
        </section>
      </div>

      {error && <pre className="text-rose-600 mt-4">{error}</pre>}
      <footer className="pt-8 text-xs text-slate-500">© {new Date().getFullYear()} iShip Vessel Inspection AI • Generated for decision support.</footer>
    </main>
  );
}

/* --- helpers --- */
function cleanText(s = "") {
  return s
    .replace(/\*\*(.*?)\*\*/g, "$1")   // remove bold markers
    .replace(/^[-*]\s*/gm, "")         // leading bullets
    .replace(/[*_`]/g, "")             // stray md chars
    .replace(/\s+/g, " ")
    .trim();
}
function splitBullets(text="") {
  const lines = text.split(/\n+/).map(s => s.trim()).filter(Boolean);
  return lines;
}

function Card({ title, value, tint="sky" }) {
  const colors = {
    emerald: "bg-emerald-50 text-emerald-700",
    rose: "bg-rose-50 text-rose-700",
    amber: "bg-amber-50 text-amber-700",
    sky: "bg-sky-50 text-sky-700",
  };
  return (
    <div className={`rounded-2xl border border-slate-200 p-4 ${colors[tint]}`}>
      <div className="text-3xl font-extrabold">{value}</div>
      <div className="text-sm opacity-80">{title}</div>
    </div>
  );
}

function Counter({ label, value, color, max = 1 }) {
  const bar =
    color === "rose" ? "bg-rose-500" :
    color === "amber" ? "bg-amber-500" :
    "bg-emerald-500";
  const pct = Math.max(4, Math.min(100, (value / Math.max(1, max)) * 100));
  return (
    <div className="mt-3">
      <div className="flex items-center justify-between text-xs text-slate-600 mb-1">
        <span>{label}</span>
        <span className="font-medium text-slate-700">{value}</span>
      </div>
      <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
        <div
          className={`h-full rounded-full ${bar} bg-[length:12px_12px]`}
          style={{
            width: `${pct}%`,
            backgroundImage:
              "repeating-linear-gradient(45deg, rgba(255,255,255,.25) 0, rgba(255,255,255,.25) 6px, transparent 6px, transparent 12px)"
          }}
        />
      </div>
    </div>
  );
}
